import Foundation

// Additional Q&A items extending MockSearchAnswersData to reach 150+ total items.
enum MockExpandedSearchAnswers {
    private static let defaultSafety = "This is general information only. For personal decisions, verify with the official institution or a qualified advisor."
    private static let fallbackURL = AppURL.make("https://www.government.nl")

    private static func item(
        question: String,
        keywords: [String],
        category: SearchCategory,
        shortAnswer: String,
        detailedAnswer: String,
        institution: String?,
        sourceName: String,
        url: String,
        isOfficial: Bool = true,
        safetyNote: String? = nil,
        relatedQuestions: [String]
    ) -> SearchAnswer {
        SearchAnswer(
            id: SearchAnswer.stableID("search-answer:\(question)"),
            question: question,
            keywords: keywords,
            category: category,
            shortAnswer: shortAnswer,
            detailedAnswer: detailedAnswer,
            relatedInstitution: institution,
            officialSourceName: sourceName,
            officialSourceURL: AppURL.validatedWebURL(URL(string: url)) ?? fallbackURL,
            isOfficialSource: isOfficial,
            safetyNote: safetyNote ?? (category.needsSafetyNote ? defaultSafety : nil),
            lastUpdated: Date(timeIntervalSince1970: 1746057600),
            relatedQuestions: relatedQuestions
        )
    }

    static let items: [SearchAnswer] = [

        // MARK: - BSN
        item(question: "What documents do I need to get a BSN?", keywords: ["bsn documents", "bsn appointment", "documents"], category: .registration, shortAnswer: "Typically a valid identity document and proof of address, but requirements vary by municipality.", detailedAnswer: "Document requirements for BSN registration can differ between municipalities. Commonly, a valid passport or identity card and address proof are needed. Always check your specific municipality's list before your appointment.", institution: "Municipality", sourceName: "Government.nl", url: "https://www.government.nl/topics/personal-data/citizen-service-number-bsn", relatedQuestions: ["How do I get a BSN?", "Do I need an appointment for BSN?"]),

        item(question: "Can I work without a BSN?", keywords: ["work without bsn", "employment bsn"], category: .work, shortAnswer: "In many cases, you should arrange a BSN as soon as possible after starting work.", detailedAnswer: "Employers typically need your BSN to process payroll and wage taxes. It is generally advisable to obtain a BSN promptly. Some limited situations may allow a temporary arrangement — verify with your employer and municipality.", institution: "Municipality", sourceName: "Government.nl", url: "https://www.government.nl/topics/personal-data/citizen-service-number-bsn", relatedQuestions: ["How do I get a BSN?", "What documents do I need to get a BSN?"]),

        item(question: "Can I open a bank account without a BSN?", keywords: ["bank account bsn", "banking bsn"], category: .registration, shortAnswer: "Some banks may open accounts without a BSN initially, but requirements differ by bank.", detailedAnswer: "Banks in the Netherlands have their own account-opening requirements. Some may accept applications before BSN is obtained. Check directly with your chosen bank for their current policy.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/personal-data/citizen-service-number-bsn", relatedQuestions: ["How do I get a BSN?", "What documents do I need to get a BSN?"]),

        item(question: "What if I lost the document showing my BSN?", keywords: ["lost bsn", "bsn document lost"], category: .registration, shortAnswer: "Contact your municipality or request a confirmation from the relevant institution.", detailedAnswer: "Your BSN is stored in the BRP. You can usually verify it via your municipality or through MijnOverheid if you have DigiD access. Do not share your BSN unnecessarily while seeking it.", institution: "Municipality", sourceName: "Government.nl", url: "https://www.government.nl/topics/personal-data/citizen-service-number-bsn", relatedQuestions: ["How do I get a BSN?", "What is DigiD?"]),

        item(question: "How long does it take to get a BSN?", keywords: ["bsn timing", "bsn how long"], category: .registration, shortAnswer: "Timing depends on municipality and appointment availability.", detailedAnswer: "In some municipalities, you receive a BSN on the same day as registration. In others, it may take longer. Check your municipality's website for expected processing times.", institution: "Municipality", sourceName: "Government.nl", url: "https://www.government.nl/topics/personal-data/citizen-service-number-bsn", relatedQuestions: ["How do I get a BSN?", "How do I register with municipality?"]),

        // MARK: - DigiD
        item(question: "Is there a DigiD mobile app?", keywords: ["digid app", "digid mobile"], category: .digid, shortAnswer: "Yes, DigiD has an official app for mobile authentication.", detailedAnswer: "The official DigiD app is available through the App Store and Google Play. Download only from official app stores. The app provides higher security for many government services. Verify details on the official DigiD website.", institution: "DigiD", sourceName: "DigiD", url: "https://www.digid.nl/en", relatedQuestions: ["What is DigiD?", "How do I activate DigiD?"]),

        item(question: "What services require DigiD?", keywords: ["digid services", "what uses digid"], category: .digid, shortAnswer: "Many Dutch government portals use DigiD including tax, healthcare, and education services.", detailedAnswer: "DigiD is used by portals such as MijnBelastingdienst, MijnUWV, DUO portals, MijnOverheid, and many healthcare-related services. The official DigiD website lists participating services.", institution: "DigiD", sourceName: "DigiD", url: "https://www.digid.nl/en", relatedQuestions: ["What is DigiD?", "How do I activate DigiD?"]),

        item(question: "What if I forgot my DigiD password?", keywords: ["forgot digid", "digid password reset"], category: .digid, shortAnswer: "Use the official DigiD password reset process.", detailedAnswer: "Visit the official DigiD website and follow the password reset procedure. You will likely need to verify your identity through official channels. Do not use unofficial third-party services.", institution: "DigiD", sourceName: "DigiD", url: "https://www.digid.nl/en", relatedQuestions: ["What is DigiD?", "How do I activate DigiD?"]),

        item(question: "Can I use DigiD outside the Netherlands?", keywords: ["digid abroad", "digid international"], category: .digid, shortAnswer: "DigiD can generally be used abroad via the app or website.", detailedAnswer: "DigiD access is generally possible from abroad using the app or website. For initial DigiD activation, you may need a Dutch residential address. Check specific requirements on the DigiD website.", institution: "DigiD", sourceName: "DigiD", url: "https://www.digid.nl/en", relatedQuestions: ["What is DigiD?", "Is there a DigiD mobile app?"]),

        item(question: "How do I use DigiD for tax filing?", keywords: ["digid tax", "belastingdienst digid"], category: .digid, shortAnswer: "Log in to MijnBelastingdienst with your DigiD to access tax filing.", detailedAnswer: "The Belastingdienst tax portal MijnBelastingdienst uses DigiD authentication. Ensure your DigiD has an appropriate security level for tax services. Instructions are on the official Belastingdienst website.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["What is Belastingdienst?", "Do I need to file a tax return?"]),

        // MARK: - Immigration / IND
        item(question: "What is an MVV visa?", keywords: ["mvv", "entry visa", "ind"], category: .immigration, shortAnswer: "An MVV (machtiging tot voorlopig verblijf) is an entry visa needed by some non-EU nationals before travelling to the Netherlands.", detailedAnswer: "Some non-EU/EEA nationals need an MVV to enter the Netherlands for longer-term stays. The MVV is applied for at an IND office or Dutch embassy/consulate. Whether you need one depends on your nationality and purpose of stay. Verify with IND.", institution: "IND", sourceName: "IND", url: "https://ind.nl/en/provisional-residence-permit-mvv", relatedQuestions: ["What is IND?", "What is the difference between MVV and residence permit?"]),

        item(question: "What is the difference between MVV and residence permit?", keywords: ["mvv residence permit difference", "ind entry visa"], category: .immigration, shortAnswer: "An MVV is an entry visa; a residence permit is what authorises living in the Netherlands long-term.", detailedAnswer: "An MVV (entry visa) allows you to enter the Netherlands. Once in the Netherlands, a residence permit (verblijfsvergunning) authorises your stay for the permitted duration. Not all permit types require an MVV. Always verify your specific route with IND.", institution: "IND", sourceName: "IND", url: "https://ind.nl/en", relatedQuestions: ["What is an MVV visa?", "What is IND?"]),

        item(question: "How do I track my IND application status?", keywords: ["ind application status", "track ind", "ind portal"], category: .immigration, shortAnswer: "Use the official IND portal or IND contact channels to check your application status.", detailedAnswer: "IND has an online portal where applicants can track the status of active applications. Use only official IND login channels. Processing times vary and are published on the IND website.", institution: "IND", sourceName: "IND", url: "https://ind.nl/en", relatedQuestions: ["What is IND?", "Where do I check residence permit information?"]),

        item(question: "What happens if my residence permit expires?", keywords: ["permit expired", "ind expired permit"], category: .immigration, shortAnswer: "An expired permit can affect your right to stay and work. Apply for renewal before expiry.", detailedAnswer: "Living in the Netherlands after your permit expires without a renewal application can have serious consequences for your legal status. IND provides renewal procedures. It is generally recommended to apply well before expiry.", institution: "IND", sourceName: "IND", url: "https://ind.nl/en", relatedQuestions: ["What is IND?", "Where do I check residence permit information?"]),

        item(question: "What is the 30% ruling for expats?", keywords: ["30 percent ruling", "expat ruling", "belastingdienst expat"], category: .taxes, shortAnswer: "The 30% ruling is a Dutch tax facility for certain highly skilled migrants.", detailedAnswer: "The 30% ruling allows eligible employees to receive part of their salary tax-free, provided they meet specific conditions including income and recruitment criteria. Conditions and duration have changed over time. Verify current rules with the Belastingdienst or a qualified tax advisor.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["What is Belastingdienst?", "How does the 30% ruling affect taxes?"]),

        item(question: "What is the IND processing time?", keywords: ["ind processing time", "ind waiting time"], category: .immigration, shortAnswer: "Processing times vary by application type and are published on the IND website.", detailedAnswer: "IND processing times differ by permit type, volume, and individual circumstances. Published timelines are estimates and can change. Check the official IND website for current indicative processing times for your permit type.", institution: "IND", sourceName: "IND", url: "https://ind.nl/en", relatedQuestions: ["How do I track my IND application status?", "What is IND?"]),

        item(question: "Do I need to report a change of address to IND?", keywords: ["ind address change", "ind notification", "ind update"], category: .immigration, shortAnswer: "Yes, you may need to inform IND of address changes in addition to municipality registration.", detailedAnswer: "IND may need to be informed of changes such as a new address. Reporting to the municipality updates the BRP, but IND may need direct notification depending on your permit type. Verify your specific obligations on official IND pages.", institution: "IND", sourceName: "IND", url: "https://ind.nl/en", relatedQuestions: ["What is IND?", "How do I change my address in the Netherlands?"]),

        item(question: "Where can I find immigration information in Dutch and English?", keywords: ["immigration english dutch", "ind english"], category: .immigration, shortAnswer: "IND publishes information in Dutch and English on their official website.", detailedAnswer: "IND.nl has an English-language section covering most permit types and procedures. Government.nl also provides English-language public information on immigration topics. Always verify the specific process for your permit type.", institution: "IND", sourceName: "IND", url: "https://ind.nl/en", relatedQuestions: ["What is IND?", "Where do I check residence permit information?"]),

        // MARK: - DUO / Education
        item(question: "What is studiefinanciering?", keywords: ["studiefinanciering", "student loan", "duo"], category: .education, shortAnswer: "Studiefinanciering is Dutch student finance that may include loans, grants, and a travel card.", detailedAnswer: "DUO's studiefinanciering scheme can include a basic grant (basistoelage or prestatiebeurs), loan, and OV-studentenkaart. Eligibility depends on nationality, permit type, and institution. Rules and conditions have changed — verify current eligibility with DUO.", institution: "DUO", sourceName: "DUO", url: "https://duo.nl/particulier/student-finance.jsp", relatedQuestions: ["What does DUO do?", "Can EU students get DUO finance?"]),

        item(question: "Does the inburgering exam affect my permit?", keywords: ["inburgering exam permit", "inburgering consequence"], category: .education, shortAnswer: "For some permit types, completing inburgering requirements can affect permit renewal.", detailedAnswer: "Some permit holders must complete inburgering within a set period. Not meeting requirements may have consequences for permit renewal or extension. Check your specific obligations with IND or DUO.", institution: "DUO / IND", sourceName: "DUO", url: "https://duo.nl/particulier/inburgeren.jsp", relatedQuestions: ["How do I find information about inburgering?", "What is IND?"]),

        item(question: "Can EU students get DUO student finance?", keywords: ["eu students duo", "eu student finance", "erasmus"], category: .education, shortAnswer: "EU/EEA students may be eligible under certain conditions — verify with DUO.", detailedAnswer: "EU/EEA students may qualify for Dutch student finance if they work in the Netherlands for a minimum number of hours per week alongside their studies. Conditions are specific — check current eligibility rules directly with DUO.", institution: "DUO", sourceName: "DUO", url: "https://duo.nl/particulier/student-finance.jsp", relatedQuestions: ["What is studiefinanciering?", "What does DUO do?"]),

        item(question: "How do I repay DUO student debt?", keywords: ["duo repay", "duo debt", "studieschuld"], category: .education, shortAnswer: "DUO repayment starts after a set period post-study and is based on income.", detailedAnswer: "After finishing studies, DUO repayment begins after a grace period. Repayment is income-dependent — you pay a percentage of income above a threshold. You can manage your repayment plan via the DUO portal. Do not ignore DUO payment notices.", institution: "DUO", sourceName: "DUO", url: "https://duo.nl/particulier/terugbetalen.jsp", relatedQuestions: ["What is studiefinanciering?", "What does DUO do?"]),

        item(question: "What is the OV-studentenkaart?", keywords: ["ov studentenkaart", "student travel card", "duo travel"], category: .education, shortAnswer: "The OV-studentenkaart is a free or discounted public transport card for eligible students.", detailedAnswer: "DUO provides eligible students with a public transport card. Conditions include active enrolment and meeting eligibility criteria. Use must stop when no longer eligible. Check DUO for current conditions.", institution: "DUO", sourceName: "DUO", url: "https://duo.nl/particulier/student-finance.jsp", relatedQuestions: ["What is studiefinanciering?", "How does the OV-chipkaart work?"]),

        // MARK: - Work / UWV
        item(question: "What is a WW-uitkering?", keywords: ["ww uitkering", "unemployment benefit", "uwv"], category: .work, shortAnswer: "A WW-uitkering is a Dutch unemployment benefit paid by UWV to eligible former employees.", detailedAnswer: "The WW (Werkloosheidswet) provides temporary unemployment benefit to employees who lose their job and meet conditions including contribution history. Eligibility, duration, and amounts depend on work history. Apply via UWV promptly after job loss.", institution: "UWV", sourceName: "UWV", url: "https://www.uwv.nl/nl/ww/ww-aanvragen?dmn=1A", relatedQuestions: ["What is UWV?", "Where do I find work-related benefits info?"]),

        item(question: "What is the minimum wage in the Netherlands?", keywords: ["minimum wage amount", "wettelijk minimumloon"], category: .work, shortAnswer: "The minimum wage is set by law and updated periodically. Check current amounts on Rijksoverheid.", detailedAnswer: "The wettelijk minimumloon (statutory minimum wage) is updated at least annually. Amounts differ by age group. Always check the current amount on the official Rijksoverheid website — do not rely on this app for exact figures.", institution: "UWV", sourceName: "Rijksoverheid", url: "https://www.rijksoverheid.nl/onderwerpen/minimumloon", relatedQuestions: ["What should I check in my work contract?", "How do I read my payslip?"]),

        item(question: "How do I read a Dutch payslip?", keywords: ["read payslip", "loonstrook", "payslip explained"], category: .work, shortAnswer: "A Dutch payslip shows gross wage, loonheffing (wage tax), and net pay.", detailedAnswer: "Key elements on a loonstrook include: bruto loon (gross wage), loonheffing (combined wage tax and social contributions), vakantiegeld (holiday pay accrual), and netto loon (net pay). Keep payslips for tax filing and applications.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["What should I check in my work contract?", "What is jaaropgave?"]),

        item(question: "What is a proeftijd in a Dutch work contract?", keywords: ["proeftijd", "probation", "trial period"], category: .work, shortAnswer: "A proeftijd is a trial/probation period at the start of employment.", detailedAnswer: "During a proeftijd, both the employer and employee can end the contract with less notice. Maximum duration depends on contract type. Not all contracts include a proeftijd. Verify the rules in your contract and on official Government.nl sources.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/themes/work", relatedQuestions: ["What should I check in my work contract?", "What is a bepaalde tijd contract?"]),

        item(question: "What is a nulurencontract (zero-hours contract)?", keywords: ["nulurencontract", "zero hours", "work hours"], category: .work, shortAnswer: "A nulurencontract offers no guaranteed hours — work is on-call.", detailedAnswer: "Under a nulurencontract, an employer can offer work as needed and the employee may decline, but rules on availability and refusal depend on the contract. Zero-hours workers still have rights — verify them with Juridisch Loket or qualified advisors.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/themes/work", relatedQuestions: ["What should I check in my work contract?", "What is UWV?"]),

        item(question: "Can I work while receiving UWV benefits?", keywords: ["work uwv benefit", "part time uwv"], category: .work, shortAnswer: "Working while receiving UWV benefits may reduce your benefit — you must report income to UWV.", detailedAnswer: "If you earn income while receiving UWV unemployment benefit, you must report it. Partial work may partially reduce the benefit amount. Not reporting can lead to overpayment demands. Verify rules with UWV directly.", institution: "UWV", sourceName: "UWV", url: "https://www.uwv.nl", relatedQuestions: ["What is a WW-uitkering?", "What is UWV?"]),

        item(question: "What is a bepaalde tijd contract?", keywords: ["bepaalde tijd", "fixed term contract"], category: .work, shortAnswer: "A bepaalde tijd contract is a fixed-term employment contract.", detailedAnswer: "A fixed-term contract has a defined end date. After a certain number of renewals or duration under Dutch law, it may convert to an indefinite contract (onbepaalde tijd). Rules on ketenregeling govern this. Verify current rules with Government.nl.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/themes/work", relatedQuestions: ["What should I check in my work contract?", "What is a nulurencontract?"]),

        item(question: "What is loonheffing?", keywords: ["loonheffing", "wage tax", "payroll tax"], category: .work, shortAnswer: "Loonheffing is the combined wage tax and social contributions withheld from your salary.", detailedAnswer: "Your employer withholds loonheffing from your gross salary each pay period and transfers it to the Belastingdienst. It includes income tax, premium for the AOW (pension), and other social premiums. The net balance is reconciled in the annual tax return.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["How do I read a Dutch payslip?", "What is Belastingdienst?"]),

        // MARK: - Taxes
        item(question: "Do I need to file an annual tax return?", keywords: ["file tax return", "aangifte inkomstenbelasting", "belasting return"], category: .taxes, shortAnswer: "Many residents in the Netherlands need to file an annual tax return. Check with Belastingdienst.", detailedAnswer: "The Belastingdienst may send a request to file (uitnodiging aangifte). Even without a direct request, you may benefit from filing if you have deductions or overpaid wage tax. New arrivals often need to file. Verify your obligation on the official Belastingdienst website.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["What is Belastingdienst?", "What is jaaropgave?"]),

        item(question: "What is jaaropgave?", keywords: ["jaaropgave", "annual statement", "year end tax"], category: .taxes, shortAnswer: "Jaaropgave is an annual income statement from your employer used for tax filing.", detailedAnswer: "Each year, your employer provides a jaaropgave showing your total gross income, loonheffing withheld, and other relevant figures. You use this to file your annual income tax return. Keep it until your tax return is finalised.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["How do I read a Dutch payslip?", "Do I need to file an annual tax return?"]),

        item(question: "What is a voorlopige aanslag?", keywords: ["voorlopige aanslag", "provisional tax"], category: .taxes, shortAnswer: "A voorlopige aanslag is a provisional tax assessment from the Belastingdienst.", detailedAnswer: "A voorlopige aanslag is an estimated tax assessment that you pay in instalments during the year. It helps prevent a large lump-sum payment at year end. You can request an adjustment if your income changes significantly. Do not ignore these letters.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["Do I need to file an annual tax return?", "What is Belastingdienst?"]),

        item(question: "What is the M-form for newcomers?", keywords: ["m form tax", "migration form", "belasting new arrival"], category: .taxes, shortAnswer: "The M-form is used by people who lived in the Netherlands for only part of a year.", detailedAnswer: "The M-form (migrant form) is a paper or digital tax form for people who arrived in or left the Netherlands during the tax year. It calculates tax proportionally for the months resident. The Belastingdienst provides instructions on when to use it.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["Do I need to file an annual tax return?", "What is Belastingdienst?"]),

        item(question: "How does the 30% ruling affect my taxes?", keywords: ["30 percent tax", "expat ruling tax"], category: .taxes, shortAnswer: "The 30% ruling allows eligible employees to receive part of their salary tax-free.", detailedAnswer: "Under the 30% ruling, eligible employees can treat 30% of their agreed salary as a tax-free allowance for extraterritorial costs. Both the employer and employee must apply. Rules have changed — check current conditions with the Belastingdienst or a tax advisor.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["What is the 30% ruling for expats?", "Do I need to file an annual tax return?"]),

        item(question: "How do I file taxes online in the Netherlands?", keywords: ["file taxes online", "mijnbelastingdienst", "aangifte online"], category: .taxes, shortAnswer: "Use MijnBelastingdienst online portal with DigiD to file your tax return.", detailedAnswer: "The Belastingdienst provides an online portal (MijnBelastingdienst) accessible via DigiD. Pre-filled information is often available. The portal guides you through each step. Deadlines for filing are published on the official site.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["What is DigiD?", "Do I need to file an annual tax return?"]),

        item(question: "What is box 3 wealth tax?", keywords: ["box 3", "wealth tax", "savings tax"], category: .taxes, shortAnswer: "Box 3 taxes returns on savings and investments above a threshold.", detailedAnswer: "Box 3 of Dutch income tax covers notional returns on savings and investments above a threshold amount. Rules have been subject to legal changes — verify the current regime directly with the Belastingdienst, as this area has seen significant updates.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["Do I need to file an annual tax return?", "What is Belastingdienst?"]),

        item(question: "What is loonheffingskorting?", keywords: ["loonheffingskorting", "tax credit", "salary credit"], category: .taxes, shortAnswer: "Loonheffingskorting is a wage tax credit that may reduce the tax withheld from your salary.", detailedAnswer: "You can request your employer applies loonheffingskorting, which reduces the amount of wage tax withheld. It can only be applied by one employer at a time. If you apply it incorrectly or with multiple employers, you may owe taxes at year end. Verify with your employer.", institution: "Belastingdienst", sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["How do I read a Dutch payslip?", "What is loonheffing?"]),

        // MARK: - Toeslagen
        item(question: "Am I eligible for huurtoeslag?", keywords: ["huurtoeslag eligible", "housing allowance eligible"], category: .taxes, shortAnswer: "Eligibility depends on income, household, and rent amount — verify on the official Toeslagen portal.", detailedAnswer: "Huurtoeslag has conditions including maximum income, rent ceilings, and property type. These thresholds change. Use the official Belastingdienst Toeslagen check tool to assess your situation.", institution: "Belastingdienst", sourceName: "Belastingdienst Toeslagen", url: "https://www.toeslagen.nl", relatedQuestions: ["What are toeslagen?", "How do I apply for toeslagen?"]),

        item(question: "Am I eligible for zorgtoeslag?", keywords: ["zorgtoeslag eligible", "health allowance eligible"], category: .healthInsurance, shortAnswer: "Zorgtoeslag eligibility depends on income and residency status.", detailedAnswer: "Whether you qualify for zorgtoeslag depends on your income, household, and residency status. Check the official Toeslagen portal for current thresholds and conditions.", institution: "Belastingdienst", sourceName: "Belastingdienst Toeslagen", url: "https://www.toeslagen.nl", relatedQuestions: ["What are toeslagen?", "Do I need health insurance?"]),

        item(question: "What is kinderopvangtoeslag?", keywords: ["kinderopvangtoeslag", "childcare allowance"], category: .taxes, shortAnswer: "Kinderopvangtoeslag is a contribution toward childcare costs for eligible parents.", detailedAnswer: "Parents who pay for registered childcare (kinderopvang) and meet income conditions may receive kinderopvangtoeslag from the Belastingdienst. Conditions change — verify on the official Toeslagen portal.", institution: "Belastingdienst", sourceName: "Belastingdienst Toeslagen", url: "https://www.toeslagen.nl", relatedQuestions: ["What are toeslagen?", "Am I eligible for huurtoeslag?"]),

        item(question: "What happens if toeslagen overpays me?", keywords: ["toeslagen overpayment", "terugbetalen toeslagen"], category: .taxes, shortAnswer: "Overpaid toeslagen must be repaid. Keep your details up to date to minimise overpayments.", detailedAnswer: "If your income or situation changes and toeslagen is not updated, overpayments can accumulate. At the annual settlement, the Belastingdienst may reclaim overpaid amounts. Report changes promptly via the official Toeslagen portal.", institution: "Belastingdienst", sourceName: "Belastingdienst Toeslagen", url: "https://www.toeslagen.nl", relatedQuestions: ["What are toeslagen?", "Can tax rules change over time?"]),

        item(question: "How do I apply for toeslagen?", keywords: ["apply toeslagen", "toeslagen aanvragen"], category: .taxes, shortAnswer: "Apply via the official Toeslagen portal using your DigiD.", detailedAnswer: "You can apply for toeslagen at any time through the Belastingdienst Toeslagen portal using DigiD. Retroactive claims are possible within certain periods. Check current rules and ensure your income details are correct.", institution: "Belastingdienst", sourceName: "Belastingdienst Toeslagen", url: "https://www.toeslagen.nl", relatedQuestions: ["What are toeslagen?", "What is DigiD?"]),

        // MARK: - Health Insurance
        item(question: "What is the basisverzekering?", keywords: ["basisverzekering", "basic health insurance", "package"], category: .healthInsurance, shortAnswer: "The basisverzekering is the legally defined basic health insurance package.", detailedAnswer: "All Dutch health insurers must offer the same basisverzekering — the basic package defined by law. The package covers general practice, hospital care, pharmacy, and more. Premiums differ between insurers even though the coverage is standardised.", institution: nil, sourceName: "Zorginstituut Nederland", url: "https://www.zorginstituutnederland.nl", relatedQuestions: ["Do I need health insurance?", "What is eigen risico?"]),

        item(question: "What is aanvullende verzekering?", keywords: ["aanvullende verzekering", "additional insurance", "health coverage"], category: .healthInsurance, shortAnswer: "Aanvullende verzekering is optional additional health coverage on top of the basic package.", detailedAnswer: "You can choose to add extra coverage (aanvullende verzekering) for things like dental care, physiotherapy, or glasses. This is optional and varies by insurer. Compare options on official comparison sources.", institution: nil, sourceName: "Zorginstituut Nederland", url: "https://www.zorginstituutnederland.nl", relatedQuestions: ["What is the basisverzekering?", "Do I need health insurance?"]),

        item(question: "What is a huisarts?", keywords: ["huisarts", "gp", "general practitioner"], category: .healthInsurance, shortAnswer: "A huisarts is a general practitioner (GP) — the first point of contact for most health issues.", detailedAnswer: "In the Dutch system, a huisarts is your first healthcare contact. Specialist referrals typically go through the huisarts. GP visits are generally exempt from the eigen risico. Register with a local huisarts as soon as possible after getting health insurance.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/health-insurance", relatedQuestions: ["Do I need health insurance?", "What is eigen risico?"]),

        item(question: "Who is exempt from mandatory health insurance?", keywords: ["health insurance exempt", "zorgverzekering exempt"], category: .healthInsurance, shortAnswer: "Exemptions are limited and condition-specific — verify on official government health pages.", detailedAnswer: "Most residents working or living in the Netherlands must have health insurance. Exemptions may apply in specific situations such as certain permit types or cross-border workers. Verify your specific situation on the official Government.nl health insurance pages.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/health-insurance", relatedQuestions: ["Do I need health insurance?", "How quickly should I arrange health insurance?"]),

        item(question: "What is the CAK?", keywords: ["cak", "health insurance cak", "administrative"], category: .healthInsurance, shortAnswer: "The CAK handles certain administrative health insurance matters including enforcement for uninsured residents.", detailedAnswer: "The CAK (Centraal Administratie Kantoor) is involved in administering health insurance for people in specific situations, including imposing an administrative measure on uninsured residents. If you receive a CAK letter, read and act on it promptly.", institution: "CAK", sourceName: "CAK", url: "https://www.hetcak.nl", relatedQuestions: ["Do I need health insurance?", "How quickly should I arrange health insurance?"]),

        item(question: "What is Zorgverzekeringswet (Zvw)?", keywords: ["zvw", "health insurance law", "zorgverzekeringswet"], category: .healthInsurance, shortAnswer: "The Zvw is the Dutch law mandating health insurance for most residents.", detailedAnswer: "The Zorgverzekeringswet (Zvw) is the law that requires eligible residents to take out basic health insurance from a private insurer. It defines the basic package and contribution system. Official sources state current requirements — verify at Government.nl.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/health-insurance", relatedQuestions: ["Do I need health insurance?", "What is the basisverzekering?"]),

        item(question: "Can I switch health insurers?", keywords: ["switch health insurer", "change health insurance"], category: .healthInsurance, shortAnswer: "You can usually switch health insurer at the end of the calendar year during an open enrolment period.", detailedAnswer: "The Dutch health insurance open enrolment window is generally in November/December for policies starting 1 January. During this period, you can switch insurer without penalty. Check cancellation conditions and ensure your new coverage starts before existing coverage ends.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/health-insurance", relatedQuestions: ["Do I need health insurance?", "What is the basisverzekering?"]),

        item(question: "What is Zorginstituut Nederland?", keywords: ["zorginstituut", "health care quality"], category: .healthInsurance, shortAnswer: "Zorginstituut Nederland sets the standards for the Dutch basic health insurance package.", detailedAnswer: "Zorginstituut Nederland advises the government on what is included in the basic health insurance package and assesses the quality of healthcare. It is a useful reference for understanding coverage rules.", institution: "Zorginstituut Nederland", sourceName: "Zorginstituut Nederland", url: "https://www.zorginstituutnederland.nl", relatedQuestions: ["What is the basisverzekering?", "What is eigen risico?"]),

        // MARK: - Housing
        item(question: "What is the huurcommissie?", keywords: ["huurcommissie", "rent dispute", "housing complaint"], category: .housing, shortAnswer: "The Huurcommissie handles rent disputes between tenants and landlords for social housing.", detailedAnswer: "The Huurcommissie is an independent authority that can mediate and rule on rent disputes. This mainly applies to social housing (huurwoning in the regulated sector). For private sector disputes, other routes may apply. Verify your situation on the Huurcommissie website.", institution: "Huurcommissie", sourceName: "Huurcommissie", url: "https://www.huurcommissie.nl", relatedQuestions: ["Where can I learn about Dutch housing basics?", "What should I check in a rental contract?"]),

        item(question: "What is borgsom (rental deposit)?", keywords: ["borgsom", "deposit", "rental deposit"], category: .housing, shortAnswer: "A borgsom is a refundable rental deposit, typically one to two months rent.", detailedAnswer: "A borgsom is paid at the start of a rental contract as security. It should be returned at the end of tenancy minus any legitimate deductions agreed in the contract. Conditions must be clearly stated in the contract. For disputes, Juridisch Loket can provide information.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/housing", relatedQuestions: ["What should I check in a rental contract?", "What is huurcommissie?"]),

        item(question: "What is a woningcorporatie?", keywords: ["woningcorporatie", "housing association", "social housing"], category: .housing, shortAnswer: "A woningcorporatie is a housing association that manages social housing.", detailedAnswer: "Woningcorporaties manage a large share of the Dutch social rental housing stock. Registration and waiting list procedures are managed locally. In major cities, waiting lists can be very long. Check your local corporatie and municipality for registration options.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/housing", relatedQuestions: ["Where can I learn about Dutch housing basics?", "Social housing — how long is the waiting list?"]),

        item(question: "What is servicekosten on a rental invoice?", keywords: ["servicekosten", "service costs", "rental invoice"], category: .housing, shortAnswer: "Servicekosten are additional charges above rent for services like cleaning, garden, or utilities.", detailedAnswer: "Landlords may charge servicekosten for specific services. There are legal limits on what can be included and how much can be charged, particularly in the social sector. Verify what is included and compare against your contract.", institution: "Huurcommissie", sourceName: "Huurcommissie", url: "https://www.huurcommissie.nl", relatedQuestions: ["What should I check in a rental contract?", "What is woningcorporatie?"]),

        item(question: "What documents do I need to rent in the Netherlands?", keywords: ["rent documents", "renting requirements"], category: .housing, shortAnswer: "Common requirements include passport, proof of income, employer statement, and sometimes a BSN.", detailedAnswer: "Landlords and agencies typically require identity documents, recent payslips or employer declaration, and sometimes a credit check or bank statement. Requirements vary. Have documents ready before viewing properties.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/housing", relatedQuestions: ["What should I check in a rental contract?", "How do I get a BSN?"]),

        item(question: "What is huurbescherming (tenant protection)?", keywords: ["huurbescherming", "tenant protection", "eviction"], category: .housing, shortAnswer: "Dutch law provides significant protections for tenants against arbitrary eviction.", detailedAnswer: "Huurrecht (rental law) gives tenants in the Netherlands strong protections. Landlords generally cannot terminate a contract without legal grounds. Conditions differ between fixed-term and open-ended contracts. For your specific situation, Juridisch Loket can provide orientation.", institution: nil, sourceName: "Juridisch Loket", url: "https://www.juridischloket.nl", isOfficial: false, relatedQuestions: ["What is huurcommissie?", "What should I check in a rental contract?"]),

        item(question: "What is a wachtlijst for social housing?", keywords: ["wachtlijst", "social housing waiting", "waiting list"], category: .housing, shortAnswer: "Social housing wachtlijst (waiting list) can be very long — registration should start early.", detailedAnswer: "In cities like Amsterdam and Rotterdam, social housing waiting lists can take many years. Registration is typically done via local woningcorporaties or regional platforms. Starting registration early even before you need housing is advisable. Verify with your local municipality or housing platform.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/housing", relatedQuestions: ["What is a woningcorporatie?", "Where can I learn about Dutch housing basics?"]),

        item(question: "What is the difference between social and private rental housing?", keywords: ["social private housing", "huur verschil"], category: .housing, shortAnswer: "Social housing has regulated lower rents; private rental is typically market-priced.", detailedAnswer: "Social housing (in the regulated sector) has rent ceilings set by law and is managed by woningcorporaties. Private rental housing has higher rents and fewer price regulations. Income limits may apply for social housing allocation. Verify current rules and thresholds.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/housing", relatedQuestions: ["What is a woningcorporatie?", "What is huurcommissie?"]),

        // MARK: - Transport
        item(question: "How does the OV-chipkaart work?", keywords: ["ov chipkaart", "public transport card", "check in out"], category: .transport, shortAnswer: "Check in at start and check out at end of each journey with the OV-chipkaart.", detailedAnswer: "The OV-chipkaart is used on trains, trams, buses, and metro. Hold your card to the reader when entering and again when exiting. Ensure sufficient balance before travel. You can manage your card at OV-chipkaart.nl or NS service points.", institution: nil, sourceName: "OV-chipkaart", url: "https://www.ov-chipkaart.nl/en", relatedQuestions: ["Where do I check vehicle registration rules?", "How do transport ticket rules work?"]),

        item(question: "What is a P+R (Park and Ride)?", keywords: ["p+r", "park and ride", "parking"], category: .transport, shortAnswer: "P+R facilities allow you to park and continue by public transport into city centres.", detailedAnswer: "P+R (Park and Ride) locations at city outskirts allow drivers to park and continue by bus, tram, or metro. Fees and conditions differ by city. Some P+R locations offer discounts with valid public transport tickets.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl/topics/mobility-public-transport-and-road-safety", relatedQuestions: ["How does the OV-chipkaart work?", "How do transport ticket rules work?"]),

        item(question: "How do I exchange my foreign driving licence for a Dutch one?", keywords: ["exchange driving licence", "foreign licence dutch", "rdw rijbewijs"], category: .transport, shortAnswer: "Check the RDW website — exchange rules depend on your country of origin.", detailedAnswer: "Exchange agreements exist with some countries allowing a direct swap. Other nationals may need a theory or practical test. The process typically involves RDW and CBR. Your permit type may also affect eligibility. Start this process early as it can take time.", institution: "RDW", sourceName: "RDW", url: "https://www.rdw.nl/en/driving-licence/foreign-driving-licence", relatedQuestions: ["What is RDW?", "Where do I check vehicle registration rules?"]),

        item(question: "What is an APK inspection?", keywords: ["apk", "vehicle inspection", "rdw"], category: .transport, shortAnswer: "APK is the mandatory periodic vehicle roadworthiness inspection in the Netherlands.", detailedAnswer: "The APK (Algemene Periodieke Keuring) is a compulsory inspection for most road vehicles. Frequency depends on vehicle age. Driving without a valid APK certificate is a traffic offence. Authorised garages perform APK inspections. Check your vehicle's APK expiry in the RDW registration certificate.", institution: "RDW", sourceName: "RDW", url: "https://www.rdw.nl/en", relatedQuestions: ["What is RDW?", "Where do I check vehicle registration rules?"]),

        item(question: "What is WAM (vehicle insurance requirement)?", keywords: ["wam", "vehicle insurance", "third party"], category: .transport, shortAnswer: "WAM is the mandatory third-party liability insurance for vehicles on Dutch roads.", detailedAnswer: "The WAM (Wet Aansprakelijkheidsverzekering Motorrijtuigen) requires all vehicles used on public roads to have at least third-party liability insurance. Driving uninsured is a serious offence. RDW tracks WAM coverage. Verify your coverage is active before driving.", institution: "RDW", sourceName: "RDW", url: "https://www.rdw.nl/en", relatedQuestions: ["What is RDW?", "What is an APK inspection?"]),

        // MARK: - CJIB / Fines
        item(question: "What happens if I do not pay a CJIB fine?", keywords: ["cjib unpaid", "fine not paid", "fine escalation"], category: .fines, shortAnswer: "Unpaid CJIB fines escalate. Ignoring them can lead to significantly higher charges.", detailedAnswer: "A CJIB fine has a payment deadline. If not paid, the fine may increase substantially with added surcharges. Further steps may include collection measures. Always pay or formally object within the deadline. Do not ignore CJIB letters.", institution: "CJIB", sourceName: "CJIB", url: "https://www.cjib.nl/en", relatedQuestions: ["What is CJIB?", "Where do I pay a traffic fine?"]),

        item(question: "What is Wahv?", keywords: ["wahv", "traffic fine law", "administratief"], category: .fines, shortAnswer: "Wahv is the Dutch law under which many traffic fines are issued administratively.", detailedAnswer: "The Wet administratiefrechtelijke handhaving verkeersvoorschriften (Wahv) allows traffic violations to be handled as administrative matters rather than criminal ones. Fines are issued by police or cameras and processed by CJIB. Objection rights and procedures are available — check official CJIB sources.", institution: "CJIB", sourceName: "CJIB", url: "https://www.cjib.nl/en", relatedQuestions: ["Where do I pay a traffic fine?", "What is CJIB?"]),

        item(question: "Can I object to a traffic fine?", keywords: ["object fine", "bezwaar fine", "cjib object"], category: .fines, shortAnswer: "You may be able to object (beroep) within the deadline stated on the CJIB notice.", detailedAnswer: "CJIB fine notices typically include information about your right to lodge a beroep (appeal). There is a strict deadline. If you miss it, the fine typically stands. The CJIB website explains the procedure. For complex disputes, legal advice may be useful.", institution: "CJIB", sourceName: "CJIB", url: "https://www.cjib.nl/en", relatedQuestions: ["What is CJIB?", "What is Wahv?"]),

        item(question: "What is DWA (kantonrechter for fines)?", keywords: ["dwa", "kantonrechter", "fine court"], category: .fines, shortAnswer: "DWA allows challenging a Wahv fine at the kantonrechter (sub-district court) after initial objection.", detailedAnswer: "If your initial beroep on a Wahv fine is rejected, you may appeal to the kantonrechter (DWA procedure). Legal guidance is advisable at this stage. Time limits are strict. Check official CJIB and Rechtspraak.nl information.", institution: "CJIB", sourceName: "CJIB", url: "https://www.cjib.nl/en", relatedQuestions: ["What is Wahv?", "Can I object to a traffic fine?"]),

        item(question: "Can fines accumulate?", keywords: ["fine accumulation", "multiple fines"], category: .fines, shortAnswer: "Yes — each fine has its own amount, deadline, and escalation path.", detailedAnswer: "Multiple outstanding fines are handled independently by CJIB. Each fine can escalate separately if not paid. Having multiple outstanding fines can put significant financial pressure on an individual. Address each fine on time.", institution: "CJIB", sourceName: "CJIB", url: "https://www.cjib.nl/en", relatedQuestions: ["What is CJIB?", "What happens if I do not pay a CJIB fine?"]),

        // MARK: - RDW
        item(question: "How do I register a foreign vehicle in the Netherlands?", keywords: ["register foreign vehicle", "rdw import", "auto registreren"], category: .transport, shortAnswer: "Contact RDW for import requirements — you will need to pay BPM tax and pass an APK inspection.", detailedAnswer: "Importing a vehicle from abroad requires registering it with RDW, potentially paying BPM (belasting van personenauto's en motorrijwielen) import tax, and ensuring the vehicle passes APK. The process depends on the vehicle's origin. Check RDW's official import information.", institution: "RDW", sourceName: "RDW", url: "https://www.rdw.nl/en", relatedQuestions: ["What is RDW?", "What is an APK inspection?"]),

        item(question: "How do I get Dutch licence plates?", keywords: ["dutch licence plates", "kenteken", "rdw plates"], category: .transport, shortAnswer: "Dutch licence plates (kenteken) are issued by RDW upon vehicle registration.", detailedAnswer: "Once your vehicle is registered with RDW, a Dutch kenteken (licence plate) is assigned. Physical plates are obtained through authorised dealers. Driving without correct plates is a traffic offence. Check RDW's registration process.", institution: "RDW", sourceName: "RDW", url: "https://www.rdw.nl/en", relatedQuestions: ["What is RDW?", "How do I register a foreign vehicle in the Netherlands?"]),

        // MARK: - Municipality
        item(question: "What is the BRP?", keywords: ["brp", "personal records", "municipality register"], category: .registration, shortAnswer: "The BRP (Basisregistratie Personen) is the official municipal personal records database.", detailedAnswer: "The BRP holds personal data including address, name, and civil status for registered residents. Many institutions use BRP data. Keeping your address and details accurate in the BRP is important for receiving official correspondence.", institution: "Municipality", sourceName: "Government.nl", url: "https://www.government.nl/topics/personal-data", relatedQuestions: ["How do I register with municipality?", "How do I change my address in the Netherlands?"]),

        item(question: "What is inschrijven bij gemeente?", keywords: ["inschrijven gemeente", "register municipality", "brp register"], category: .registration, shortAnswer: "Inschrijven means registering your address and personal details with your municipality.", detailedAnswer: "Inschrijven bij gemeente is the formal registration process at your local municipality. You register your address, provide identity documents, and are entered in the BRP. This is typically how you obtain a BSN.", institution: "Municipality", sourceName: "Government.nl", url: "https://www.government.nl/topics/municipalities", relatedQuestions: ["How do I register with municipality?", "What is the BRP?"]),

        item(question: "What is deregistration from BRP?", keywords: ["deregistration brp", "uitschrijven gemeente", "leaving netherlands"], category: .registration, shortAnswer: "When permanently leaving the Netherlands, you should deregister from the BRP.", detailedAnswer: "Uitschrijven (deregistration) removes your address registration from the BRP when you leave the Netherlands permanently. This can affect tax and benefit obligations. Contact your municipality to arrange deregistration before or shortly after leaving.", institution: "Municipality", sourceName: "Government.nl", url: "https://www.government.nl/topics/municipalities", relatedQuestions: ["How do I change my address in the Netherlands?", "What is the BRP?"]),

        item(question: "What is a VOG (certificate of good conduct)?", keywords: ["vog", "certificate of good conduct", "antecedentenverklaring"], category: .registration, shortAnswer: "A VOG is an official document confirming no relevant criminal record.", detailedAnswer: "A Verklaring Omtrent het Gedrag (VOG) is often required by employers, schools, or volunteer organisations. It is issued by the Ministry of Justice and Security via Justis. Applications can typically be submitted online using DigiD.", institution: "Justis", sourceName: "Government.nl", url: "https://www.justis.nl/en", relatedQuestions: ["How do I register with municipality?", "What is DigiD?"]),

        item(question: "What documents do I need to register with the municipality?", keywords: ["register documents", "gemeente documents", "brp documents"], category: .registration, shortAnswer: "Typically a valid passport or ID, and proof of address — check your specific municipality's requirements.", detailedAnswer: "Document requirements vary by municipality but typically include a valid identity document and address proof (tenancy contract or landlord statement). Some municipalities may require additional documents. Always verify with your specific municipality's website before your appointment.", institution: "Municipality", sourceName: "Government.nl", url: "https://www.government.nl/topics/municipalities", relatedQuestions: ["How do I register with municipality?", "What is the BRP?"]),

        // MARK: - Emergency
        item(question: "What is 0900-8844 (non-urgent police)?", keywords: ["0900-8844", "police non urgent", "politie"], category: .emergency, shortAnswer: "0900-8844 is the non-urgent police line for reporting incidents that are not emergencies.", detailedAnswer: "Use 0900-8844 (Politie) for non-urgent police matters such as reporting a theft, filing a complaint, or requesting assistance where there is no immediate danger. For emergencies, call 112.", institution: "Politie", sourceName: "Politie.nl", url: "https://www.politie.nl", relatedQuestions: ["What is the emergency number in the Netherlands?", "When should I call 112?"]),

        item(question: "What is the GGD?", keywords: ["ggd", "public health", "health service"], category: .emergency, shortAnswer: "GGD is the regional public health service in the Netherlands.", detailedAnswer: "GGD (Gemeentelijke Gezondheidsdienst) is the regional public health authority. It is involved in vaccination, infectious disease control, and public health monitoring. If you have a public health concern or need a vaccination, your local GGD can provide information.", institution: nil, sourceName: "RIVM", url: "https://www.rivm.nl/en", relatedQuestions: ["What is the emergency number in the Netherlands?", "Where do I find non-urgent help?"]),

        item(question: "What mental health crisis lines exist in the Netherlands?", keywords: ["mental health crisis", "crisis helpline", "suicide prevention"], category: .emergency, shortAnswer: "113 Suicide Prevention is a 24/7 helpline. Call or chat online.", detailedAnswer: "For mental health crises, you can contact 113 (Zelfmoordpreventie) 24/7. There are also support services for various groups. Your huisarts is also a primary contact for mental health referrals. In acute danger, call 112.", institution: nil, sourceName: "113.nl", url: "https://www.113.nl/", relatedQuestions: ["What is the emergency number in the Netherlands?", "What is a huisarts?"]),

        // MARK: - Scam Prevention
        item(question: "How do I recognise a fake Belastingdienst message?", keywords: ["fake belastingdienst", "belasting scam", "phishing tax"], category: .general, shortAnswer: "The Belastingdienst does not ask for payments via SMS links or unexpected emails.", detailedAnswer: "Scam messages impersonating Belastingdienst may ask for urgent payment via a link. Official sources state that Belastingdienst uses physical mail, the MijnBelastingdienst portal, and official contact channels — not random SMS payment links. Verify any message at the official Belastingdienst website before acting.", institution: nil, sourceName: "Belastingdienst", url: "https://www.belastingdienst.nl", relatedQuestions: ["How do I avoid scam websites?", "I got a suspicious SMS about payment, what now?"]),

        item(question: "What is phone spoofing?", keywords: ["spoofing", "fake caller id", "scam call"], category: .general, shortAnswer: "Spoofing is when a scammer makes a call appear to come from an official institution.", detailedAnswer: "Scammers can fake the caller ID so it appears to be a government institution, bank, or utility. If you receive an unexpected call requesting personal data or payment, hang up and call the institution back using a number from their official website.", institution: nil, sourceName: "Fraudehelpdesk", url: "https://www.fraudehelpdesk.nl", isOfficial: false, relatedQuestions: ["How do I avoid scam websites?", "How do I recognise a fake Belastingdienst message?"]),

        item(question: "What is Fraudehelpdesk?", keywords: ["fraudehelpdesk", "fraud report", "scam report netherlands"], category: .general, shortAnswer: "Fraudehelpdesk is the Dutch national contact point for fraud and online scam reports.", detailedAnswer: "Fraudehelpdesk.nl is the Dutch organisation where you can report suspicious messages, websites, and fraud attempts. They also publish warnings about active scam campaigns. Check their website if you receive a suspicious message before acting.", institution: nil, sourceName: "Fraudehelpdesk", url: "https://www.fraudehelpdesk.nl", isOfficial: false, relatedQuestions: ["How do I avoid scam websites?", "How do I report online fraud concerns?"]),

        item(question: "What should I do if I think I have been a victim of identity fraud?", keywords: ["identity fraud", "identiteitsfraude", "data stolen"], category: .general, shortAnswer: "Report to police, contact affected institutions, and freeze access where possible.", detailedAnswer: "If you suspect identity fraud, contact the Politie (police) to file a report, contact affected financial institutions, and if DigiD was compromised, change credentials immediately via the official DigiD website. The Fraudehelpdesk can advise on next steps.", institution: nil, sourceName: "Fraudehelpdesk", url: "https://www.fraudehelpdesk.nl", isOfficial: false, relatedQuestions: ["How do I avoid scam websites?", "I got a suspicious SMS about payment, what now?"]),

        item(question: "How do I avoid fake rental listings?", keywords: ["rental scam", "fake housing ad", "housing fraud"], category: .general, shortAnswer: "Verify the landlord's identity and never pay a deposit before signing a contract.", detailedAnswer: "Fake rental listings may show attractive properties at below-market prices with pressure to pay deposits quickly. Legitimate landlords provide a viewable property, sign a contract before deposits, and have verifiable identities. Check Fraudehelpdesk for known scams and use reputable platforms.", institution: nil, sourceName: "Fraudehelpdesk", url: "https://www.fraudehelpdesk.nl", isOfficial: false, relatedQuestions: ["How do I avoid scam websites?", "What should I check in a rental contract?"]),

        // MARK: - Legal Help
        item(question: "What is rechtsbijstand (legal aid)?", keywords: ["rechtsbijstand", "legal aid", "subsidised lawyer"], category: .legalHelp, shortAnswer: "Rechtsbijstand is a subsidised legal assistance system for those who cannot afford private lawyers.", detailedAnswer: "If you have a limited income, you may qualify for subsidised legal aid (toevoeging) via the Raad voor Rechtsbijstand. A lawyer will be assigned at a reduced contribution. Eligibility depends on income. Apply through a lawyer or the Juridisch Loket.", institution: "Juridisch Loket", sourceName: "Juridisch Loket", url: "https://www.juridischloket.nl", isOfficial: false, relatedQuestions: ["Where can I get legal help about letters?", "What is a toevoeging?"]),

        item(question: "What is a toevoeging?", keywords: ["toevoeging", "legal aid certificate", "subsidised lawyer"], category: .legalHelp, shortAnswer: "A toevoeging is a certificate entitling you to subsidised legal representation.", detailedAnswer: "If you qualify for legal aid, the Raad voor Rechtsbijstand issues a toevoeging that allows a lawyer to represent you at a reduced client contribution. You pay a set income-dependent contribution. Apply via your lawyer or Juridisch Loket.", institution: "Juridisch Loket", sourceName: "Juridisch Loket", url: "https://www.juridischloket.nl", isOfficial: false, relatedQuestions: ["What is rechtsbijstand?", "Where can I get legal help about letters?"]),

        item(question: "What is a gerechtsdeurwaarder (bailiff)?", keywords: ["gerechtsdeurwaarder", "bailiff", "enforcement"], category: .legalHelp, shortAnswer: "A gerechtsdeurwaarder is a court officer who can enforce judgments and collect debts.", detailedAnswer: "A gerechtsdeurwaarder has legal authority to serve summonses, collect court-ordered payments, and seize assets. If you receive a notice from one, enforcement is already underway. Seek qualified legal advice immediately and do not ignore the notice.", institution: nil, sourceName: "Juridisch Loket", url: "https://www.juridischloket.nl", isOfficial: false, relatedQuestions: ["Where can I get legal help about letters?", "What is rechtsbijstand?"]),

        item(question: "What is a vonnis (court judgment)?", keywords: ["vonnis", "court judgment", "rechtbank"], category: .legalHelp, shortAnswer: "A vonnis is a legally binding court judgment.", detailedAnswer: "A vonnis is a decision made by a rechtbank (court). It is legally binding on the parties. If a vonnis is issued against you, it may be enforced by a gerechtsdeurwaarder. Appeals may be possible within set deadlines. Seek legal advice when dealing with court judgments.", institution: nil, sourceName: "Rechtspraak.nl", url: "https://www.rechtspraak.nl/English", relatedQuestions: ["What is Rechtspraak.nl?", "Where can I get legal help about letters?"]),

        item(question: "What is Rechtspraak.nl?", keywords: ["rechtspraak", "dutch courts", "court information"], category: .legalHelp, shortAnswer: "Rechtspraak.nl is the official website of the Dutch court system.", detailedAnswer: "Rechtspraak.nl provides public information about the Dutch court system, how to initiate proceedings, and court locations. It is not a replacement for qualified legal advice. Use it for general orientation about courts and procedures.", institution: nil, sourceName: "Rechtspraak.nl", url: "https://www.rechtspraak.nl/English", relatedQuestions: ["Where can I get legal help about letters?", "What is a vonnis?"]),

        // MARK: - General / Administrative
        item(question: "What is a kenmerk on a government letter?", keywords: ["kenmerk", "reference number", "letter reference"], category: .general, shortAnswer: "A kenmerk is a case reference number — include it in all replies to that institution.", detailedAnswer: "The kenmerk is a unique identifier for your case or document. When contacting the institution about that letter, always quote the kenmerk so they can locate your file quickly. It is typically found at the top of official correspondence.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl", relatedQuestions: ["What should I do with official letters?", "How do I verify if a government letter is real?"]),

        item(question: "What is aangetekende post?", keywords: ["aangetekende post", "registered mail", "signature post"], category: .general, shortAnswer: "Aangetekende post is registered mail requiring a signature upon delivery.", detailedAnswer: "When a letter is sent aangetekend (registered), you must sign for it on delivery. If you are not home, a collection notice is left and you can pick it up at a PostNL point. Important legal and official documents are often sent this way.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl", relatedQuestions: ["What should I do with official letters?", "Do I need to keep copies of official letters?"]),

        item(question: "What is a DigiD machtiging (authorisation)?", keywords: ["digid machtiging", "digid authorisation", "power of attorney"], category: .digid, shortAnswer: "A DigiD machtiging lets someone act on your behalf in official portals.", detailedAnswer: "A DigiD machtiging allows a trusted person (such as a family member) to log in and act on your behalf in specific government portals. It must be authorised through the official MijnOverheid machtiging system. Only use this with fully trusted individuals.", institution: "DigiD", sourceName: "DigiD", url: "https://www.digid.nl/en", relatedQuestions: ["What is DigiD?", "What is MijnOverheid?"]),

        item(question: "What is MijnOverheid?", keywords: ["mijnoverheid", "government portal", "berichtenbox"], category: .general, shortAnswer: "MijnOverheid is a secure government portal where official messages are delivered digitally.", detailedAnswer: "MijnOverheid is a secure online portal where you can receive official communications from many Dutch government institutions. Accessible with DigiD. Some institutions use it as the primary communication channel, so check it regularly after setting up DigiD.", institution: nil, sourceName: "Government.nl", url: "https://www.mijnoverheid.nl", relatedQuestions: ["What is DigiD?", "What should I do with official letters?"]),

        item(question: "How do I read Dutch dates on official letters?", keywords: ["dutch dates", "date format", "dd mm yyyy"], category: .general, shortAnswer: "Dutch dates are typically written as day-month-year (e.g., 15-04-2025).", detailedAnswer: "Official Dutch documents typically use the DD-MM-YYYY format. For example, 15-04-2025 means April 15, 2025. Deadline dates in letters use this format. Ensure you read the month and day in the correct order to avoid confusion.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl", relatedQuestions: ["What should I do with official letters?", "What is a kenmerk on a government letter?"]),

        item(question: "What is a PostNL pickup point?", keywords: ["postnl", "parcel pickup", "pakket ophalen"], category: .general, shortAnswer: "PostNL delivers Dutch mail and parcels — undelivered items can be collected at pickup points.", detailedAnswer: "PostNL is the primary Dutch postal and parcel delivery service. If you miss a delivery, a note is left with instructions to collect from a nearby PostNL point (often a supermarket or shop). Track deliveries and collect promptly as holding times are limited.", institution: nil, sourceName: "Government.nl", url: "https://www.government.nl", relatedQuestions: ["What is aangetekende post?", "Do I need to keep copies of official letters?"])
